export default function ImportarProductos() {
  const [loading, setLoading] = useState(false);
  const [progress, setProgress] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const [borrandoTodo, setBorrandoTodo] = useState(false);

  const handleImportar = async () => {
    if (!confirm("\u00BFImportar " + PRODUCTOS_SELOGAS.length + " productos del cat\u00E1logo Repsol? Si ya tienes productos, c\u00E1mbialos o b\u00F3rralos primero.")) return;
    setLoading(true);
    setError(null);
    setResult(null);
    try {
      setProgress("Preparando categor\u00EDas...");
      const catNombres = [...new Set(PRODUCTOS_SELOGAS.map(p => p.categoria).filter(Boolean))];
      const catMap = {};
      for (const nombre of catNombres) {
        let { data: existing } = await supabase.from("categorias").select("id").eq("nombre", nombre).single();
        if (existing) {
          catMap[nombre] = existing.id;
        } else {
          const { data: created, error: catErr } = await supabase.from("categorias").insert([{ nombre, activa: true }]).select("id").single();
          if (catErr) throw catErr;
          catMap[nombre] = created.id;
        }
      }
      setProgress("Importando productos...");
      let created = 0;
      const total = PRODUCTOS_SELOGAS.length;
      const productos = PRODUCTOS_SELOGAS.map((p, i) => {
        const { categoria, ...rest } = p;
        return {
          ...rest,
          categoria_id: catMap[categoria] || null,
          orden_excel: i,
          disponible: true,
          grupo_visualizacion: p.grupo_visualizacion || "ambas",
          hoja_excel: categoria,
          multiplo: p.multiplo || 1,
        };
      });
      for (let i = 0; i < productos.length; i += 50) {
        const batch = productos.slice(i, i + 50);
        const { error: insertError } = await supabase.from("productos").insert(batch);
        if (insertError) throw insertError;
        created += batch.length;
        setProgress("Guardando... " + created + "/" + total);
      }
      setResult({ total: created });
    } catch (e) {
      setError(e.message || "Error al importar");
    } finally {
      setLoading(false);
      setProgress("");
    }
  };

  const handleBorrarTodo = async () => {
    if (!confirm("\u00BFEst\u00E1s seguro? Esto borrar\u00E1 TODOS los productos del cat\u00E1logo.")) return;
    setBorrandoTodo(true);
    try {
      const { error: deleteError } = await supabase.from("productos").delete().neq("id", "00000000-0000-0000-0000-000000000000");
      if (deleteError) throw deleteError;
      alert("Productos borrados.");
    } catch(e) {
      alert("Error: " + e.message);
    } finally {
      setBorrandoTodo(false);
    }
  };

  const categorias = [...new Set(PRODUCTOS_SELOGAS.map(p => p.categoria))];

  return (
    <div className="max-w-2xl mx-auto">
      <div className="bg-white rounded-2xl shadow-sm border p-8" style={{ borderColor: "var(--color-border)" }}>
        <h1 className="text-2xl font-bold mb-2">Importar Cat&aacute;logo Repsol</h1>
        <p className="text-gray-500 mb-1 text-sm">
          Cat&aacute;logo completo de <strong>tutienda.repsol.es</strong> con {PRODUCTOS_SELOGAS.length} productos en {categorias.length} categor\u00EDas.
        </p>
        <p className="text-gray-400 mb-6 text-xs">Im&aacute;genes incluidas &bull; Categor&iacute;as auto-creadas &bull; Multiplos configurados</p>

        <div className="grid grid-cols-3 gap-3 mb-6 text-center">
          {categorias.slice(0, 9).map(cat => {
            const count = PRODUCTOS_SELOGAS.filter(p => p.categoria === cat).length;
            return (
              <div key={cat} className="bg-gray-50 rounded-xl p-3 border">
                <div className="font-semibold text-sm text-gray-800 truncate">{cat}</div>
                <div className="text-xs text-gray-500 mt-0.5">{count} prods</div>
              </div>
            );
          })}
        </div>

        {progress && (
          <div className="mb-4 p-3 bg-blue-50 rounded-xl text-blue-700 text-sm font-medium flex items-center gap-2">
            <Loader2 size={16} className="animate-spin" />
            {progress}
          </div>
        )}
        {error && (
          <div className="mb-4 p-3 bg-red-50 rounded-xl text-red-700 text-sm flex items-center gap-2">
            <AlertCircle size={16} />
            {error}
          </div>
        )}
        {result && (
          <div className="mb-4 p-3 bg-green-50 rounded-xl text-green-700 text-sm font-medium flex items-center gap-2">
            <CheckCircle size={16} />
            &iexcl;Importados {result.total} productos correctamente!
          </div>
        )}

        <div className="flex gap-3">
          <button
            onClick={handleImportar}
            disabled={loading}
            className="flex-1 py-3 px-4 rounded-xl font-bold text-white flex items-center justify-center gap-2 disabled:opacity-60"
            style={{ background: "var(--color-primary)" }}
          >
            {loading ? <Loader2 size={18} className="animate-spin" /> : <Upload size={18} />}
            {loading ? "Importando..." : "Importar " + PRODUCTOS_SELOGAS.length + " Productos"}
          </button>
          <button
            onClick={handleBorrarTodo}
            disabled={borrandoTodo || loading}
            className="px-4 py-3 rounded-xl font-bold text-red-600 border-2 border-red-200 hover:bg-red-50 flex items-center gap-2 disabled:opacity-60"
          >
            {borrandoTodo ? <Loader2 size={18} className="animate-spin" /> : <Trash2 size={18} />}
            Borrar todo
          </button>
        </div>

        <div className="mt-6 pt-4 border-t">
          <h3 className="font-semibold text-sm text-gray-700 mb-3 flex items-center gap-2">
            <Database size={14} /> {categorias.length} Categor\u00EDas
          </h3>
          <div className="flex flex-wrap gap-2">
            {categorias.map(cat => {
              const count = PRODUCTOS_SELOGAS.filter(p => p.categoria === cat).length;
              return (
                <span key={cat} className="px-2.5 py-1 bg-gray-100 rounded-full text-xs text-gray-600">
                  {cat} ({count})
                </span>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}
